cleanedText = cleanedText.replace(/'/g, '');
cleanedText = cleanedText.replace(/`/g, '');
cleanedText = cleanedText.replace(/\{/g, '');
cleanedText = cleanedText.replace(/\}/g, '');
cleanedText = cleanedText.replace(/\[/g, '');
cleanedText = cleanedText.replace(/\]/g, '');
cleanedText = cleanedText.replace(/ +/g, ' ').trim();

return [
  {
    json: {
      ClearPromt: cleanedText,
    }
  }
];

const inputText = $input.first().json.data;

// Регулярное выражение для извлечения значения authSid из CDATA
const regex = /<authSid><!\[CDATA\[(.*?)\]\]><\/authSid>/;

// Извлекаем значение
const match = inputText.match(regex);

// Возвращаем только найденное значение или пустую строку, если не найдено
return {
  json: {
    authSid: match ? match[1] : ""
  }
};

