old_array = _items

len_old_array = len(old_array)
len_of_success = 0

for elem in old_array:
    json_data = elem.get("json", {})

    # Если ключ отсутствует → успех
    # Если ключ есть и равен False → тоже успех
    if json_data.get("error_generation", False) is False:
        len_of_success += 1

return [{
    "json": {
        "len_old_array": len_old_array,
        "len_of_success": len_of_success
    }
}]

